/*
 * aterm-security C API
 *
 * Command validation and security policy for terminal applications.
 * Implements CaMeL-style tiered command access control.
 *
 * Tier system:
 *   0 = Safe       (ls, cat, pwd)
 *   1 = Low Risk   (mkdir, touch, cp)
 *   2 = Medium Risk (curl, wget, git)
 *   3 = High Risk  (sudo, rm -rf, chmod)
 *   4 = Critical   (reboot, dd, mkfs)
 *
 * Quick start:
 *   AtermCommandValidator *v = aterm_command_validator_new(2);
 *   AtermValidationResult r = aterm_command_validate(v, "curl https://...");
 *   if (r.status == ATERM_VALIDATION_STATUS_ALLOWED) { ... }
 *   aterm_validation_result_free(&r);
 *   aterm_command_validator_free(v);
 *
 * Thread Safety: All functions are NOT thread-safe.
 * Callers must ensure exclusive access to validator instances.
 */


